import{_ as o,o as a,c as s,ag as t}from"./chunks/framework.BPmc_f4o.js";const m=JSON.parse('{"title":"brut build-assets","description":"","frontmatter":{},"headers":[],"relativePath":"brut-cli-commands/build-assets.md","filePath":"brut-cli-commands/build-assets.md"}'),r={name:"brut-cli-commands/build-assets.md"};function d(l,e,i,n,c,h){return a(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="brut-build-assets" tabindex="-1"><code>brut build-assets</code> <a class="header-anchor" href="#brut-build-assets" aria-label="Permalink to &quot;`brut build-assets`&quot;">​</a></h1><p>Build and manage code and assets destined for the browser, such as CSS, JS, or images</p><h2 id="usage" tabindex="-1">USAGE <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;USAGE&quot;">​</a></h2><pre><code>brut build-assets [options] command\n</code></pre><h2 id="options" tabindex="-1">OPTIONS <a class="header-anchor" href="#options" aria-label="Permalink to &quot;OPTIONS&quot;">​</a></h2><ul><li><code>--env=ENVIRONMENT</code> - Project environment, e.g. test, development, production. Default depends on the command</li><li><code>--log-level=LOG_LEVEL</code> - Log level, which should be debug, info, warn, error, or fatal. Defaults to error</li><li><code>--debug, --verbose</code> - Set log level to debug, and show log messages on stdout</li><li><code>--quiet</code> - Set log level to error</li><li><code>--log-file=FILE</code> - Path to a file where log messages are written. Defaults to $XDG_CACHE_HOME/brut/logs/brut.log</li><li><code>--[no-]log-stdout</code> - Log messages to stdout in addition to the log file</li><li><code>--help, -h</code> - Show help</li></ul><h2 id="commands" tabindex="-1">COMMANDS <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;COMMANDS&quot;">​</a></h2><h3 id="all" tabindex="-1"><a href="./commands/all.html"><code>all</code></a> <a class="header-anchor" href="#all" aria-label="Permalink to &quot;[`all`](./commands/all)&quot;">​</a></h3><p>Build all assets</p><h3 id="css" tabindex="-1"><a href="./commands/css.html"><code>css</code></a> <a class="header-anchor" href="#css" aria-label="Permalink to &quot;[`css`](./commands/css)&quot;">​</a></h3><p>Builds a single CSS file suitable for sending to the browser</p><p>This produces a hashed file in every environment, in order to keep environments consistent and reduce differences. If your CSS file references images, fonts, or other assets via <code>url()</code> or other CSS functions, those files will be hashed and copied into the output directory where CSS is served.</p><p>To ensure this happens correctly, your <code>url()</code> or other function must reference the file as a relative file from where your actual source CSS file is located. For example, a font named <code>some-font.ttf</code> would be in <code>app/src/front_end/fonts</code>. To reference this from <code>app/src/front_end/css/index.css</code> you&#39;d use <code>url(&quot;../fonts/some-font.ttf&quot;)</code></p><h3 id="images" tabindex="-1"><a href="./commands/images.html"><code>images</code></a> <a class="header-anchor" href="#images" aria-label="Permalink to &quot;[`images`](./commands/images)&quot;">​</a></h3><p>Copy images to the public folder</p><p>This is to ensure that any images your code references will end up in the public directory, so they are served properly. This is not for managing images that may be referenced in CSS files. See the <code>css</code> command for information on that.</p><h3 id="js" tabindex="-1"><a href="./commands/js.html"><code>js</code></a> <a class="header-anchor" href="#js" aria-label="Permalink to &quot;[`js`](./commands/js)&quot;">​</a></h3><p>Builds and bundles JavaScript destined for the browser</p>',18)])])}const f=o(r,[["render",d]]);export{m as __pageData,f as default};
